        var limits = ReadmeSource.IndexOf("\n## Limits", StringComparison.Ordinal);
        var deepLinking = ReadmeSource.IndexOf("\n## Deep Linking", StringComparison.Ordinal);

        Assert.True(configurationTail >= 0,
